export const updateScenarioBodyCommissionConfigBaseSalaryMin = 0;

export const updateScenarioBodyCommissionConfigBaseCommissionPercentMin = 0;
export const updateScenarioBodyCommissionConfigBaseCommissionPercentMax = 100;

export const updateScenarioBodyCommissionConfigTiersItemMinClientsMin = 0;

export const updateScenarioBodyCommissionConfigTiersItemPercentMin = 0;
export const updateScenarioBodyCommissionConfigTiersItemPercentMax = 100;


export const updateScenarioBodyServicesItemPriceMin = 0;





export const UpdateScenarioBody = zod.object({
  "name": zod.string().min(1).optional(),
  "businessType": zod.enum(['barbershop', 'salon', 'nail', 'spa', 'custom']).optional(),
  "employeeCount": zod.number().min(1).optional(),
  "workingDaysPerMonth": zod.number().min(1).max(updateScenarioBodyWorkingDaysPerMonthMax).optional(),
  "workingHoursPerDay": zod.number().min(1).max(updateScenarioBodyWorkingHoursPerDayMax).optional(),
  "fixedCosts": zod.number().min(updateScenarioBodyFixedCostsMin).optional(),
  "targetProfit": zod.number().min(updateScenarioBodyTargetProfitMin).optional(),
  "commissionModel": zod.enum(['flat', 'base_plus_commission', 'tiered']).optional(),
  "commissionConfig": zod.object({
  "flatPercent": zod.number().min(updateScenarioBodyCommissionConfigFlatPercentMin).max(updateScenarioBodyCommissionConfigFlatPercentMax).nullish(),
  "baseSalary": zod.number().min(updateScenarioBodyCommissionConfigBaseSalaryMin).nullish(),
  "baseCommissionPercent": zod.number().min(updateScenarioBodyCommissionConfigBaseCommissionPercentMin).max(updateScenarioBodyCommissionConfigBaseCommissionPercentMax).nullish(),
  "tiers": zod.array(zod.object({
  "minClients": zod.number().min(updateScenarioBodyCommissionConfigTiersItemMinClientsMin),
  "percent": zod.number().min(updateScenarioBodyCommissionConfigTiersItemPercentMin).max(updateScenarioBodyCommissionConfigTiersItemPercentMax)
})).nullish()
}).optional(),
  "services": zod.array(zod.object({
  "name": zod.string().min(1),
  "price": zod.number().min(updateScenarioBodyServicesItemPriceMin),
  "durationMinutes": zod.number().min(1)
})).min(1).optional()
})

export const updateScenarioResponseModuleTypeDefault = `target_mundur`;

export const UpdateScenarioResponse = zod.object({
  "id": zod.number(),
  "name": zod.string(),
  "moduleType": zod.string().default(updateScenarioResponseModuleTypeDefault),
  "moduleInput": zod.record(zod.string(), zod.unknown()).nullish(),
  "businessType": zod.string(),
  "employeeCount": zod.number(),
  "workingDaysPerMonth": zod.number(),
  "workingHoursPerDay": zod.number(),
  "fixedCosts": zod.number(),
  "targetProfit": zod.number(),
  "commissionModel": zod.string(),
  "commissionConfig": zod.record(zod.string(), zod.unknown()),
  "services": zod.array(zod.record(zod.string(), zod.unknown())),
  "resultSnapshot": zod.record(zod.string(), zod.unknown()),
  "createdAt": zod.coerce.date(),
  "updatedAt": zod.coerce.date()
})


